const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const cleaned = raw.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);
const now = new Date().toISOString();
const visitId = `V${Date.now()}`;
const input = $item(0).$node['Webhook Upload'].json.body;

return [{
  json: {
    visitId,
    patientName: input.patientName || 'Unknown',
    recordingText: input.recordingText || '',
    doctorAdvice: parsed.doctorAdvice || input.doctorAdvice || '',
    createdAt: now,
    ...parsed,
    medicationsJson: JSON.stringify(parsed.medications || []),
    instructionsJson: JSON.stringify(parsed.instructions || []),
    redFlagsJson: JSON.stringify(parsed.redFlags || []),
    followUpJson: JSON.stringify(parsed.followUp || {})
  }
}];

const meds = $json.medications || [];
const patientName = $json.patientName;
const visitId = $json.visitId;
const now = new Date().toISOString();

const out = [];
for (const med of meds) {
  const timingRaw = String(med.timing || '').trim();
  if (!timingRaw || timingRaw.toLowerCase() === 'chua duoc chi dinh') continue;
  const slots = timingRaw.split(/[+,;\/]/).map(s => s.trim()).filter(Boolean);
  for (const time of slots) {
    out.push({
      json: {
        reminder_id: `R_${visitId}_${Date.now()}_${Math.floor(Math.random()*10000)}`,
        visit_id: visitId,
        patient_name: patientName,
        medication_name: med.name || '',
        dosage: med.dosage || '',
        time_slot: time,
        frequency: med.frequency || '',
        completed: 'FALSE',
        last_reminder: now
      }
    });
  }
}

return out;
